import React from 'react'

const Content = (items,handleChange,changeDelete,setItems) => {
  return (
   <main>
    {
    <ol>
      {items.map(items => (
        <li key={items.id}>
          <label onDoubleClick={()=>handleChange(items.id)}
                 style={(items.checked) ? {textDecoration:'line-through'}:null}>
                    {items.activity}
          </label>
          <input type="checkbox" checked={items.checked} onChange={()=>handleChange(items.id)} />
          <button onClick={()=>changeDelete(items.id)}>Delete</button>
        </li>
      ))}
    </ol>
      }
   </main>
  )
}

export default Content






